parameters.jsCode:
const articles = $input.first().json.articles || [];

return articles.map(article => ({
  json: article
}));

const rows = $input.all();

const clientsData = rows.map(item => {
  const row = item.json;

  const splitField = (value) => {
    if (!value) return [];
    return String(value)
      .split('|')
      .map(v => v.trim())
      .filter(Boolean);
  };

  return {
    sr_no: row["Sr. No."] || "",
    client_name: row["Client Name"] || "",
    profile: row["Profile"] || "",
    risk_appetite: row["Risk Appetite"] || "",
    goals: splitField(row["Goals"]),
    holdings: splitField(row["Holdings"]),
    sector_exposure: splitField(row["Sector Exposure"]),
    geography_exposure: splitField(row["Geography Exposure"]),
    sensitivity: splitField(row["Sensitivity"]),
  };
});

return [
  {
    json: {
      clientsData
    }
  }
];

const rows = $input.all();

const normalizeUrl = (value) => {
  if (!value) return '';
  try {
    const u = new URL(String(value).trim());
    return `${u.origin}${u.pathname}`.trim();
  } catch {
    return String(value).trim().split('?')[0];
  }
};

const loggedUrls = rows
  .map(item => item.json?.["Normalized URL"] || item.json?.["Article URL"] || '')
  .filter(url => !!url)
  .map(url => normalizeUrl(url));

return [
  {
    json: {
      loggedUrls
    }
  }
];

const article = $input.first().json;

const normalizeUrl = (value) => {
  if (!value) return '';
  try {
    const u = new URL(String(value).trim());
    return `${u.origin}${u.pathname}`.trim();
  } catch {
    return String(value).trim().split('?')[0];
  }
};

const currentUrl = String(article.url || '').trim();
const normalizedUrl = normalizeUrl(currentUrl);

const loggedUrls =
  $items("Build Logged URL List")[0]?.json?.loggedUrls || [];

const alreadyLogged = loggedUrls.includes(normalizedUrl);

return [
  {
    json: {
      ...article,
      normalizedUrl,
      alreadyLogged
    }
  }
];
